        "title": "Assignment 2: Job Scheduler using Min/Max Heap",
        "complexity": "O(log n) Time for Insert/Delete",
        "code": "import java.util.*;\n\nclass Job{\n    String name;\n    int exec_time;\n\n    Job(String name,int exec_time){\n        this.name=name;\n        this.exec_time=exec_time;\n    }\n}\n\nclass Max_Heap{\n\n    int capacity=100;\n    Job[] jobs=new Job[capacity];\n    int size=-1;\n\n    public void insert(Job new_job){\n\n        if(size==capacity-1){\n            System.out.println(\"Heap Capacity Reached!!\");\n            return;\n        }\n\n        size++;\n        jobs[size]=new_job;\n\n        int i=size;\n        int parent=(i-1)/2;\n\n        while(i>0 &&\n              jobs[i].exec_time>jobs[parent].exec_time){\n\n            Job temp=jobs[parent];\n            jobs[parent]=jobs[i];\n            jobs[i]=temp;\n\n            i=parent;\n            parent=(i-1)/2;\n        }\n\n        System.out.println(\"Successful Insertion in Max Heap!!\");\n    }\n\n    public void delete_max(){\n\n        if(size==-1){\n            System.out.println(\"Heap is Empty!!\");\n            return;\n        }\n\n        jobs[0]=jobs[size];\n        jobs[size]=null;\n        size--;\n\n        int i=0;\n\n        while(i<=size){\n\n            int left=2*i+1;\n            int right=2*i+2;\n            int largest=i;\n\n            if(left<=size &&\n               jobs[left].exec_time>jobs[largest].exec_time){\n\n                largest=left;\n            }\n\n            if(right<=size &&\n               jobs[right].exec_time>jobs[largest].exec_time){\n\n                largest=right;\n            }\n\n            if(largest==i) break;\n\n            Job temp=jobs[largest];\n            jobs[largest]=jobs[i];\n            jobs[i]=temp;\n\n            i=largest;\n        }\n\n        System.out.println(\"Deleted Highest Priority Job from Max Heap\");\n    }\n\n    public void peek(){\n\n        if(size==-1){\n            System.out.println(\"Heap is Empty!!\");\n        }\n        else{\n            System.out.println(\n                \"Highest Priority Job: \"\n                +jobs[0].name+\n                \" : \"+\n                jobs[0].exec_time\n            );\n        }\n    }\n\n    public void display(){\n\n        if(size==-1){\n            System.out.println(\"Heap is Empty!!\");\n            return;\n        }\n\n        System.out.println(\"\\nMax Heap Jobs:\");\n\n        for(int i=0;i<=size;i++){\n\n            System.out.println(\n                jobs[i].name+\n                \" : \"+\n                jobs[i].exec_time\n            );\n        }\n    }\n}\n\nclass Min_Heap{\n\n    int capacity=100;\n    Job[] jobs=new Job[capacity];\n    int size=-1;\n\n    public void insert(Job new_job){\n\n        if(size==capacity-1){\n            System.out.println(\"Heap Capacity Reached!!\");\n            return;\n        }\n\n        size++;\n        jobs[size]=new_job;\n\n        int i=size;\n        int parent=(i-1)/2;\n\n        while(i>0 &&\n              jobs[i].exec_time<jobs[parent].exec_time){\n\n            Job temp=jobs[parent];\n            jobs[parent]=jobs[i];\n            jobs[i]=temp;\n\n            i=parent;\n            parent=(i-1)/2;\n        }\n\n        System.out.println(\"Successful Insertion in Min Heap!!\");\n    }\n\n    public void delete_min(){\n\n        if(size==-1){\n            System.out.println(\"Heap is Empty!!\");\n            return;\n        }\n\n        jobs[0]=jobs[size];\n        jobs[size]=null;\n        size--;\n\n        int i=0;\n\n        while(i<=size){\n\n            int left=2*i+1;\n            int right=2*i+2;\n            int smallest=i;\n\n            if(left<=size &&\n               jobs[left].exec_time<jobs[smallest].exec_time){\n\n                smallest=left;\n            }\n\n            if(right<=size &&\n               jobs[right].exec_time<jobs[smallest].exec_time){\n\n                smallest=right;\n            }\n\n            if(smallest==i) break;\n\n            Job temp=jobs[smallest];\n            jobs[smallest]=jobs[i];\n            jobs[i]=temp;\n\n            i=smallest;\n        }\n\n        System.out.println(\"Deleted Highest Priority Job from Min Heap\");\n    }\n\n    public void peek(){\n\n        if(size==-1){\n            System.out.println(\"Heap is Empty!!\");\n        }\n        else{\n\n            System.out.println(\n                \"Highest Priority Job: \"\n                +jobs[0].name+\n                \" : \"+\n                jobs[0].exec_time\n            );\n        }\n    }\n\n    public void display(){\n\n        if(size==-1){\n            System.out.println(\"Heap is Empty!!\");\n            return;\n        }\n\n        System.out.println(\"\\nMin Heap Jobs:\");\n\n        for(int i=0;i<=size;i++){\n\n            System.out.println(\n                jobs[i].name+\n                \" : \"+\n                jobs[i].exec_time\n            );\n        }\n    }\n}\n\npublic class practice{\n\n    public static void main(String[] args){\n\n        Scanner sc=new Scanner(System.in);\n\n        Max_Heap maxHeap=new Max_Heap();\n        Min_Heap minHeap=new Min_Heap();\n\n        int choice;\n\n        do{\n\n            System.out.println(\"\\n===== JOB SCHEDULER USING HEAP =====\");\n\n            System.out.println(\"1. Insert Job in Min Heap\");\n            System.out.println(\"2. Delete Highest Priority Job from Min Heap\");\n            System.out.println(\"3. Peek Min Heap\");\n            System.out.println(\"4. Display Min Heap\");\n\n            System.out.println(\"5. Insert Job in Max Heap\");\n            System.out.println(\"6. Delete Highest Priority Job from Max Heap\");\n            System.out.println(\"7. Peek Max Heap\");\n            System.out.println(\"8. Display Max Heap\");\n\n            System.out.println(\"9. Exit\");\n\n            System.out.print(\"Enter Choice: \");\n            choice=sc.nextInt();\n\n            switch(choice){\n\n                case 1:\n\n                    System.out.print(\"Enter Job Name: \");\n                    String minName=sc.next();\n\n                    System.out.print(\"Enter Execution Time: \");\n                    int minTime=sc.nextInt();\n\n                    minHeap.insert(new Job(minName,minTime));\n                    break;\n\n                case 2:\n                    minHeap.delete_min();\n                    break;\n\n                case 3:\n                    minHeap.peek();\n                    break;\n\n                case 4:\n                    minHeap.display();\n                    break;\n\n                case 5:\n\n                    System.out.print(\"Enter Job Name: \");\n                    String maxName=sc.next();\n\n                    System.out.print(\"Enter Execution Time: \");\n                    int maxTime=sc.nextInt();\n\n                    maxHeap.insert(new Job(maxName,maxTime));\n                    break;\n\n                case 6:\n                    maxHeap.delete_max();\n                    break;\n\n                case 7:\n                    maxHeap.peek();\n                    break;\n\n                case 8:\n                    maxHeap.display();\n                    break;\n\n                case 9:\n                    System.out.println(\"Exiting...\");\n                    break;\n\n                default:\n                    System.out.println(\"Invalid Choice!!\");\n            }\n\n        }while(choice!=9);\n\n        sc.close();\n    }\n}",
